import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from datetime import datetime
import uuid

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get('STORAGE_ACCOUNT_URL', 'https://<storage-account>.blob.core.windows.net')
COSMOS_ENDPOINT = os.environ.get('COSMOS_ENDPOINT', 'https://<cosmos-account>.documents.azure.com:443/')
COSMOS_DATABASE = os.environ.get('COSMOS_DATABASE', 'processeddata')
COSMOS_CONTAINER = os.environ.get('COSMOS_CONTAINER', 'results')
EVENT_GRID_ENDPOINT = os.environ.get('EVENT_GRID_ENDPOINT', 'https://<topic>.eventgrid.azure.net/api/events')
BLOB_CONTAINER_NAME = os.environ.get('BLOB_CONTAINER_NAME', 'input-files')

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_ENDPOINT, credential=credential)

# Get Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE)
container = database.get_container_client(COSMOS_CONTAINER)


@app.blob_trigger(arg_name="myblob", path=f"{BLOB_CONTAINER_NAME}/{{name}}", connection="STORAGE_ACCOUNT_URL")
def blob_processor(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file
        processed_data = process_file(myblob.name, blob_content)
        
        # Write to Cosmos DB
        cosmos_result = write_to_cosmos(processed_data)
        logging.info(f"Written to Cosmos DB: {cosmos_result['id']}")
        
        # Send Event Grid notification
        send_event_grid_notification(myblob.name, cosmos_result['id'], "success")
        logging.info(f"Event Grid notification sent for {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        send_event_grid_notification(myblob.name, None, "error", str(e))
        raise


def process_file(filename: str, content: bytes) -> dict:
    """Process file content and return structured data"""
    
    # Determine file type and process accordingly
    file_extension = filename.split('.')[-1].lower()
    
    processed_data = {
        'id': str(uuid.uuid4()),
        'filename': filename,
        'processed_at': datetime.utcnow().isoformat(),
        'file_size': len(content),
        'file_type': file_extension,
        'status': 'processed'
    }
    
    # Process based on file type
    if file_extension == 'json':
        try:
            json_data = json.loads(content.decode('utf-8'))
            processed_data['data'] = json_data
            processed_data['record_count'] = len(json_data) if isinstance(json_data, list) else 1
        except Exception as e:
            processed_data['error'] = str(e)
            processed_data['status'] = 'error'
    
    elif file_extension == 'txt':
        text_content = content.decode('utf-8')
        processed_data['line_count'] = len(text_content.split('\n'))
        processed_data['word_count'] = len(text_content.split())
        processed_data['summary'] = text_content[:200]
    
    elif file_extension == 'csv':
        text_content = content.decode('utf-8')
        lines = text_content.split('\n')
        processed_data['row_count'] = len(lines)
        processed_data['column_count'] = len(lines[0].split(',')) if lines else 0
    
    else:
        processed_data['content_type'] = 'binary'
        processed_data['note'] = 'Binary file processed'
    
    return processed_data


def write_to_cosmos(data: dict) -> dict:
    """Write processed data to Cosmos DB"""
    
    # Add partition key if needed
    if 'partitionKey' not in data:
        data['partitionKey'] = data.get('filename', data['id'])
    
    # Create or upsert item
    result = container.upsert_item(body=data)
    logging.info(f"Successfully written item {result['id']} to Cosmos DB")
    
    return result


def send_event_grid_notification(filename: str, cosmos_id: str, status: str, error_message: str = None):
    """Send notification to Event Grid"""
    
    event_data = {
        'filename': filename,
        'cosmos_id': cosmos_id,
        'status': status,
        'timestamp': datetime.utcnow().isoformat()
    }
    
    if error_message:
        event_data['error_message'] = error_message
    
    cloud_event = CloudEvent(
        type='FileProcessing.Completed' if status == 'success' else 'FileProcessing.Failed',
        source='azure-function-blob-processor',
        data=event_data,
        subject=f'file/{filename}'
    )
    
    event_grid_client.send([cloud_event])
    logging.info(f"Event Grid notification sent: {status}")


@app.route(route="health", auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint"""
    
    health_status = {
        'status': 'healthy',
        'timestamp': datetime.utcnow().isoformat(),
        'services': {}
    }
    
    # Check Blob Storage connection
    try:
        blob_service_client.get_service_properties()
        health_status['services']['blob_storage'] = 'connected'
    except Exception as e:
        health_status['services']['blob_storage'] = f'error: {str(e)}'
        health_status['status'] = 'unhealthy'
    
    # Check Cosmos DB connection
    try:
        database.read()
        health_status['services']['cosmos_db'] = 'connected'
    except Exception as e:
        health_status['services']['cosmos_db'] = f'error: {str(e)}'
        health_status['status'] = 'unhealthy'
    
    # Check Event Grid
    try:
        health_status['services']['event_grid'] = 'configured'
    except Exception as e:
        health_status['services']['event_grid'] = f'error: {str(e)}'
    
    status_code = 200 if health_status['status'] == 'healthy' else 503
    
    return func.HttpResponse(
        json.dumps(health_status),
        status_code=status_code,
        mimetype='application/json'
    )


@app.route(route="process-manual", auth_level=func.AuthLevel.FUNCTION, methods=["POST"])
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """Manually trigger processing of a specific blob"""
    
    try:
        req_body = req.get_json()
        blob_name = req_body.get('blob_name')
        container_name = req_body.get('container_name', BLOB_CONTAINER_NAME)
        
        if not blob_name:
            return func.HttpResponse(
                json.dumps({'error': 'blob_name is required'}),
                status_code=400,
                mimetype='application/json'
            )
        
        # Get blob client
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        # Download blob
        blob_data = blob_client.download_blob().readall()
        
        # Process the file
        processed_data = process_file(blob_name, blob_data)
        
        # Write to Cosmos DB
        cosmos_result = write_to_cosmos(processed_data)
        
        # Send Event Grid notification
        send_event_grid_notification(blob_name, cosmos_result['id'], "success")
        
        return func.HttpResponse(
            json.dumps({
                'status': 'success',
                'cosmos_id': cosmos_result['id'],
                'message': f'Successfully processed {blob_name}'
            }),
            status_code=200,
            mimetype='application/json'
        )
        
    except Exception as e:
        logging.error(f"Error in manual processing: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            status_code=500,
            mimetype='application/json'
        )


@app.route(route="results/{id}", auth_level=func.AuthLevel.FUNCTION, methods=["GET"])
def get_result(req: func.HttpRequest) -> func.HttpResponse:
    """Retrieve processing result from Cosmos DB"""
    
    try:
        result_id = req.route_params.get('id')
        
        if not result_id:
            return func.HttpResponse(
                json.dumps({'error': 'id is required'}),
                status_code=400,
                mimetype='application/json'
            )
        
        # Query Cosmos DB
        item = container.read_item(item=result_id, partition_key=result_id)
        
        return func.HttpResponse(
            json.dumps(item),
            status_code=200,
            mimetype='application/json'
        )
        
    except Exception as e:
        logging.error(f"Error retrieving result: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            status_code=404 if 'not found' in str(e).lower() else 500,
            mimetype='application/json'
        )